import React, { useEffect, useRef } from 'react';
import { StyleSheet, View, StatusBar, Platform, AppState } from 'react-native';
import { WebView } from 'react-native-webview';
import * as Notifications from 'expo-notifications';
import * as Device from 'expo-device';

// ─── HTML (base64) ───
const HTML_B64 = '';
const HTML_URI = 'data:text/html;base64,' + HTML_B64;

// ─── Bildirim ayarları ───
Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: true,
  }),
});

const MSGS = {
  breakfast: [
    { title: '🌅 Kahvaltı Vakti!', body: 'Güne enerjik bir başlangıç için kahvaltını yapma zamanı!' },
    { title: '☀️ Günaydın!', body: 'Sağlıklı bir güne başlamak için kahvaltını atlamayı unutma.' },
  ],
  lunch: [
    { title: '☀️ Öğle Yemeği Zamanı!', body: 'Öğle molası geldi! Menüne göz at.' },
    { title: '🍱 Öğle Molası!', body: 'Yarım günlük enerjini tazele.' },
  ],
  dinner: [
    { title: '🌙 Akşam Yemeği Vakti!', body: 'Aile sofrası sizi bekliyor!' },
    { title: '🍽️ Akşam Sofrası!', body: 'Sevdiklerinizle sıcak bir akşam yemeği keyfi.' },
  ],
  water: [
    { title: '💧 Su İçme Vakti!', body: 'Hemen bir bardak su iç!' },
    { title: '🚰 Susadın mı?', body: 'Günde 2 litre su içmeyi hedefle.' },
  ],
};

const rand = arr => arr[Math.floor(Math.random() * arr.length)];

async function registerNotifs() {
  if (!Device.isDevice) return null;
  const { status: ex } = await Notifications.getPermissionsAsync();
  let st = ex;
  if (ex !== 'granted') {
    const { status } = await Notifications.requestPermissionsAsync();
    st = status;
  }
  if (st !== 'granted') return null;
  if (Platform.OS === 'android') {
    await Notifications.setNotificationChannelAsync('meals', {
      name: 'Öğün Hatırlatıcıları',
      importance: Notifications.AndroidImportance.HIGH,
      vibrationPattern: [0, 250, 250, 250],
      lightColor: '#D4622A',
    });
    await Notifications.setNotificationChannelAsync('water', {
      name: 'Su Hatırlatıcısı',
      importance: Notifications.AndroidImportance.DEFAULT,
    });
  }
  return st;
}

async function setupNotifs(s) {
  await Notifications.cancelAllScheduledNotificationsAsync();
  const bf = (s && s.breakfast) || { enabled: true, time: '08:00' };
  const ln = (s && s.lunch)     || { enabled: true, time: '12:00' };
  const dn = (s && s.dinner)    || { enabled: true, time: '19:00' };
  const wt = (s && s.water)     || { enabled: true, intervalMin: 120 };
  if (bf.enabled) {
    const [h,m] = (bf.time||'08:00').split(':').map(Number);
    const msg = rand(MSGS.breakfast);
    await Notifications.scheduleNotificationAsync({
      content: { title: msg.title, body: msg.body, sound: 'default', data: { type: 'breakfast' } },
      trigger: { hour: h, minute: m, repeats: true, channelId: 'meals' },
    });
  }
  if (ln.enabled) {
    const [h,m] = (ln.time||'12:00').split(':').map(Number);
    const msg = rand(MSGS.lunch);
    await Notifications.scheduleNotificationAsync({
      content: { title: msg.title, body: msg.body, sound: 'default', data: { type: 'lunch' } },
      trigger: { hour: h, minute: m, repeats: true, channelId: 'meals' },
    });
  }
  if (dn.enabled) {
    const [h,m] = (dn.time||'19:00').split(':').map(Number);
    const msg = rand(MSGS.dinner);
    await Notifications.scheduleNotificationAsync({
      content: { title: msg.title, body: msg.body, sound: 'default', data: { type: 'dinner' } },
      trigger: { hour: h, minute: m, repeats: true, channelId: 'meals' },
    });
  }
  if (wt.enabled) {
    const interval = Math.floor((wt.intervalMin||120) / 60);
    for (let h = 8; h < 22; h += interval) {
      const msg = rand(MSGS.water);
      await Notifications.scheduleNotificationAsync({
        content: { title: msg.title, body: msg.body, sound: 'default', data: { type: 'water' } },
        trigger: { hour: h, minute: 0, repeats: true, channelId: 'water' },
      });
    }
  }
}

const BRIDGE_JS = `
(function() {
  window.NATIVE_NOTIF_READY = true;
  window.sendToNative = function(d) {
    if (window.ReactNativeWebView) window.ReactNativeWebView.postMessage(JSON.stringify(d));
  };
  window.addEventListener('message', function(e) {
    try {
      var m = JSON.parse(e.data);
      if (m.type === 'NOTIFICATION') {
        var ico = m.notifType === 'water' ? '💧' : m.notifType === 'breakfast' ? '🌅' : m.notifType === 'lunch' ? '☀️' : '🌙';
        if (typeof showToast === 'function') showToast(ico, m.title, m.body);
        if (typeof addNotifLog === 'function') addNotifLog(m.title, m.body, m.notifType);
      }
      if (m.type === 'NOTIF_TAP' && typeof goSec === 'function') goSec('notif');
      if (m.type === 'PERMISSION_RESULT') {
        if (typeof updatePermUI === 'function') updatePermUI(m.granted ? 'granted' : 'denied');
        if (m.granted && typeof showToast === 'function') showToast('✅', 'Bildirim İzni Verildi!', 'Öğün ve su hatırlatmaları aktif.');
      }
      if (m.type === 'NOTIF_SETTINGS_SAVED' && typeof showToast === 'function') showToast('✅', 'Ayarlar Kaydedildi', 'Bildirim saatleri güncellendi.');
    } catch(err) {}
  });
  document.addEventListener('DOMContentLoaded', function() {
    setTimeout(function() {
      var btn = document.getElementById('notifPermBtn');
      if (btn) btn.onclick = function() { window.sendToNative({ type: 'REQUEST_PERMISSION' }); };
      var msg = document.getElementById('notifPermMsg');
      var st = document.getElementById('notifPermStatus');
      if (msg) msg.textContent = 'Native bildirim sistemi hazır. Uygulama kapalıyken de bildirim alırsınız.';
      if (st) st.textContent = '📱';
      var origSave = window.saveNotifSettings;
      window.saveNotifSettings = function() {
        if (origSave) origSave();
        var settings = typeof getNotifSettings === 'function' ? getNotifSettings() : null;
        if (settings) window.sendToNative({ type: 'SAVE_NOTIF_SETTINGS', settings: settings });
      };
      window.testNotif = function(type) {
        window.sendToNative({ type: 'TEST_NOTIF', notifType: type });
        if (typeof showToast === 'function') showToast('✅', 'Test Gönderildi!', '2 saniye içinde gelecek.');
      };
    }, 1500);
  });
})();
true;
`;

export default function App() {
  const webRef = useRef(null);
  const appState = useRef(AppState.currentState);
  const notifListener = useRef();
  const responseListener = useRef();

  useEffect(() => {
    (async () => {
      const status = await registerNotifs();
      if (status === 'granted') await setupNotifs(null);
    })();

    notifListener.current = Notifications.addNotificationReceivedListener(n => {
      webRef.current?.postMessage(JSON.stringify({
        type: 'NOTIFICATION',
        title: n.request.content.title,
        body: n.request.content.body,
        notifType: n.request.content.data?.type,
      }));
    });

    responseListener.current = Notifications.addNotificationResponseReceivedListener(r => {
      webRef.current?.postMessage(JSON.stringify({
        type: 'NOTIF_TAP',
        notifType: r.notification.request.content.data?.type,
      }));
    });

    const sub = AppState.addEventListener('change', next => {
      if (appState.current.match(/inactive|background/) && next === 'active') {
        webRef.current?.postMessage(JSON.stringify({ type: 'APP_RESUMED' }));
      }
      appState.current = next;
    });

    return () => {
      notifListener.current && Notifications.removeNotificationSubscription(notifListener.current);
      responseListener.current && Notifications.removeNotificationSubscription(responseListener.current);
      sub.remove();
    };
  }, []);

  const handleMsg = async (event) => {
    try {
      const msg = JSON.parse(event.nativeEvent.data);
      if (msg.type === 'SAVE_NOTIF_SETTINGS') {
        await setupNotifs(msg.settings);
        webRef.current?.postMessage(JSON.stringify({ type: 'NOTIF_SETTINGS_SAVED', success: true }));
      }
      if (msg.type === 'TEST_NOTIF') {
        const m = rand(MSGS[msg.notifType] || MSGS.water);
        await Notifications.scheduleNotificationAsync({
          content: { title: m.title, body: m.body, sound: 'default' },
          trigger: { seconds: 2 },
        });
      }
      if (msg.type === 'REQUEST_PERMISSION') {
        const status = await registerNotifs();
        const granted = status === 'granted';
        webRef.current?.postMessage(JSON.stringify({ type: 'PERMISSION_RESULT', granted }));
        if (granted) await setupNotifs(null);
      }
      if (msg.type === 'CANCEL_ALL') {
        await Notifications.cancelAllScheduledNotificationsAsync();
      }
    } catch (e) { console.log('msg err:', e); }
  };

  return (
    <View style={{ flex: 1, backgroundColor: '#1C0A00' }}>
      <StatusBar barStyle="light-content" backgroundColor="#1C0A00" />
      <WebView
        ref={webRef}
        source={{ uri: HTML_URI }}
        style={{ flex: 1 }}
        injectedJavaScriptBeforeContentLoaded={BRIDGE_JS}
        onMessage={handleMsg}
        javaScriptEnabled={true}
        domStorageEnabled={true}
        allowFileAccess={true}
        allowUniversalAccessFromFileURLs={true}
        originWhitelist={['*']}
        mixedContentMode="always"
        bounces={false}
        overScrollMode="never"
        showsVerticalScrollIndicator={false}
      />
    </View>
  );
}
